### Generate an image
# @name generateImage
POST {{host}}/generations/image
Authorization: Bearer {{token}}
Content-Type: application/json
Accept: application/json

{
  "generation_type": "image",
  "model": "photon-1",
  "prompt": "string",
  "aspect_ratio": "16:9",
  "format": "jpg",
  "callback_url": "https://example.com",
  "image_ref": [
    {
      "url": "https://example.com",
      "weight": 0
    }
  ],
  "style_ref": [
    {
      "url": "https://example.com",
      "weight": 0
    }
  ],
  "character_ref": {
    "identity0": {
      "images": []
    }
  },
  "modify_image_ref": {
    "url": "https://example.com",
    "weight": 0
  },
  "sync": false,
  "sync_timeout": 60
}

